class Solution:
    def minStable(self, nums: List[int], maxC: int) -> int:
        n = len(nums)
        res = n
        for i in range(n):
            hcf = nums[i]
            for j in range(i, n):
                hcf = self.gcd(hcf, nums[j])
                if hcf < 2:
                    break
                res = min(res, j - i + 1)
        for i in range(n):
            for j in range(i + 1, n):
                if self.gcd(nums[i], nums[j]) < 2:
                    break
                res = min(res, j - i)
        return min(res, maxC)
